static int eye_img_task(void *param) {
    (void*)param;
    while (1) {
        if (wifi_config_mode) {
            goldie_msleep(300);
            LabelView_right_word->setText("配网模式", 55, 70);
            LabelView_left_word->setText("配网模式", 55, 70);
            if (wifi_service->svr_sta_isConnected()) {
                char* current_ssid = wifi_service->svr_sta_connection_name();
                if (current_ssid) {
                // 如果之前有记录SSID，且当前SSID不同 → 配网成功
                // 如果之前没记录SSID（未连接），现在有SSID → 配网成功
                if (wifi_ssid_before_config[0] == '\0' || 
                    strcmp(current_ssid, wifi_ssid_before_config) != 0) {
                    
                    wifi_config_mode = 0;
                    LabelView_left_word->setVisible(false);
                    LabelView_right_word->setVisible(false);
                    LabelView_left->setVisible(true);
                    LabelView_right->setVisible(true);
                    LabelView_left->setImageBuffer((uint16_t*)&rgb16_wink_4_160_160);
                    LabelView_right->setImageBuffer((uint16_t*)&rgb16_wink_4_160_160);
                    }
                }
            }else{
            // WiFi未连接，确保眼睛隐藏，只显示文字
            LabelView_left->setVisible(false);
            LabelView_right->setVisible(false);
            LabelView_left_word->setVisible(true);
            LabelView_right_word->setVisible(true);
            LabelView_right_word->setText("配网模式", 55, 70);
            LabelView_left_word->setText("配网模式", 55, 70);
            // 每3秒重启一次SoftAP，确保配网模式可用
            static int softap_restart_cnt = 0;
            softap_restart_cnt++;
                if (softap_restart_cnt >= 10) {
                    softap_restart_cnt = 0;
                    if (!wifi_service->svr_softap_isEnabled()) {
                        printf("[eye_img_task] SoftAP was closed, restarting...\n");
                        char ap_ssid[] = "xiaohe";
                        char ap_password[] = "12345678";
                        wifi_service->svr_softap_config(ap_ssid, ap_password);
                        wifi_service->trigger_event(WIFI_EVENT_SOFTAP_ENABLE, NULL);
                    }
                }
            }
        }else{
        update_status();
        // 更新状态机
        if ((cloud_service_st == CLOUD_STATUS_STOPED) || (cloud_service_st == CLOUD_STATUS_SLEEPED)) {
            play_type = PLAY_TYPE_SLEEP;
        } else {
            if (cloud_speak_st == CLOUD_SPEAK_STATUS_SILENCE) {
                play_type = PLAY_TYPE_SILENCE;
            } else {
                play_type = PLAY_TYPE_SPEAK;
            }
        }

        // 更新头像UI（眼睛）
        update_avatar_ui(play_type);
        }
    }
    return 0;
}


static int priv_atoi(char* str) {
    int str_len = strlen(str);
    if (str_len < 3) {
        return 0;
    }
    if ((str[0] == 'i') && (str[1] == 'd') && (str[2] == '_')) {
        return atoi(str + 3);
    }
    return 0;
}

static void update_status() {
    if (cloud_service) {
        char* cfg_str = cloud_service->get_config(CONFIG_AVATAR);
        avatar_id = priv_atoi(cfg_str);
        cloud_service_st = cloud_service->get_status();
        cloud_speak_st = cloud_service->get_speak_status();
        // 获取情绪并转换为枚举
        char* emotion_str = cloud_service->get_config(EMOTION);
        if (emotion_str) {
            if (strcmp(emotion_str, "happy") == 0) {
                current_emotion = EMOTION_HAPPY;
            } else if (strcmp(emotion_str, "angry") == 0) {
                current_emotion = EMOTION_ANGRY;
            } else if (strcmp(emotion_str, "sad") == 0) {
                current_emotion = EMOTION_SAD;
            } else if (strcmp(emotion_str, "doubt") == 0) {
                current_emotion = EMOTION_DOUBT;
            } else {
                current_emotion = EMOTION_NEUTRAL;
            }
        // printf("\r\n\r\nemotion: %s\r\n\r\n", emotion_str);
        }
    }
}

