static void goldie_app_run(void)
{
    main_ui_init();
    LabelView_left->setImageBuffer((uint16_t*)&rgb16_wink_4_160_160);
    LabelView_right->setImageBuffer((uint16_t*)&rgb16_wink_4_160_160);
 // 服务初始化
    mevtservice = (EventService*)wait_service(EVENT_SERVICE_INDEX);
    if (mevtservice) {
        mevtservice->register_broadcast_recv(EVENT_BROADCAST_ADDMSG, add_msg);
    }

    cloud_service = (CloudService*)wait_service(CLOUD_SERVICE_INDEX);
    if (cloud_service) {
        cloud_service->register_status_callback(cloud_status_callback);
        cloud_service_st = cloud_service->get_status();
    }

    wifi_service = (WifiService*)wait_service(WIFI_SERVICE_INDEX);
    
    if (wifi_service) {
        for (int i = 0; i < 50; i++) {  // 等待5秒（50次 × 100ms）
            if (wifi_service->svr_sta_isConnected()) {
                wifi_config_mode = 0;  // 已连接，正常模式
                LabelView_left->setVisible(true);
                LabelView_right->setVisible(true);
                LabelView_left_word->setVisible(false);
                LabelView_right_word->setVisible(false);
                break;
            }
            goldie_msleep(100);
            if (i == 49) {
                wifi_config_mode = 1;  // 5秒后仍未连接，进入配网模式
                LabelView_left->setVisible(false);
                LabelView_right->setVisible(false);
                LabelView_left_word->setVisible(true);
                LabelView_right_word->setVisible(true);
                char ap_ssid[] = "xiaohe";
                char ap_password[] = "12345678";
                wifi_service->svr_softap_config(ap_ssid, ap_password);
                wifi_service->trigger_event(WIFI_EVENT_SOFTAP_ENABLE, NULL);
            }
        }
    } else {
        goldie_msleep(50);
        wifi_config_mode = 1;  // 没有WiFi服务，直接进入配网模式
        LabelView_left->setVisible(true);
        LabelView_right->setVisible(true);
        LabelView_left_word->setVisible(false);
        LabelView_right_word->setVisible(false);
        char ap_ssid[] = "xiaohe";
        char ap_password[] = "12345678";
        wifi_service->svr_softap_config(ap_ssid, ap_password);
        wifi_service->trigger_event(WIFI_EVENT_SOFTAP_ENABLE, NULL);
    }

    goldie_thread_lock();
    task_handle = goldie_thread_create((goldie_thread_handler)eye_img_task, 0, 
                                       "eye_img_task", 0x1000);
    if (task_handle) {
    goldie_thread_set_priority(task_handle, 24);  // 设置线程优先级
    }
    goldie_thread_unlock();
}

static void goldie_app_suspend(void)
{
    window_suspend();
}

static void goldie_app_resume(void)
{
    window_resume();
    
}

static void goldie_app_exit(void)
{
    window_exit();
    // 销毁线程资源
    if (task_handle != NULL) {
        goldie_thread_destroy(task_handle);
        task_handle = NULL;
    }
}

