static App_t dualscreen_ai_app = {
    "dualscreen_ai",       // app_name char*
    goldie_app_run,       // h_app_run
    goldie_app_exit,      // h_app_exit
    goldie_app_suspend,   // h_app_suspend
    goldie_app_resume,    // h_app_resume
    goldie_touch_event,   // h_touch_event
    goldie_keyboard_event,// h_keyboard_event
    (uint16_t*)gImage_default_icon,             
};

static void goldie_keyboard_event(int pressure, int key)
{
    static unsigned int ts[5] = {0};
    static unsigned char count = 0;

    // 只监测左键（HOME键）按下
    if (key == 301 && pressure == 1) {
        goldie_timeval tv;
        goldie_gettimeofday(&tv);
        unsigned int now_ms = (unsigned int)(tv.tv_sec * 1000 + tv.tv_usec / 1000);

        // 超时重置：首次按下 或 距第一次按下超过 3000ms
        if (count == 0 || (now_ms - ts[0] > 3000)) {
            count = 0;
        }

        ts[count] = now_ms;
        count++;

        if (count >= 5) {
            count = 0;  // 重置计数

            // 1. 断开云服务
            if (cloud_service == NULL) {
                cloud_service = (CloudService*)wait_service(CLOUD_SERVICE_INDEX);
            }
            if (cloud_service != NULL) {
                cloud_service->triger_event(CLOUD_EVENT_STOP);
                printf("[DualScreen] 5-click -> cloud service stopped\n");
            }

            // 2. 重启 WiFi
            if (wifi_service == NULL) {
                wifi_service = (WifiService*)wait_service(WIFI_SERVICE_INDEX);
            }
            if (wifi_service != NULL) {
                  // 记录当前连接的WiFi名称
                if (wifi_service->svr_sta_isConnected()) {
                    char* name = wifi_service->svr_sta_connection_name();
                    if (name) {
                        strncpy(wifi_ssid_before_config, name, sizeof(wifi_ssid_before_config) - 1);
                        printf("[DualScreen] Record current WiFi: %s\n", wifi_ssid_before_config);
                    }
                } else {
                    wifi_ssid_before_config[0] = '\0';  // 未连接，清空
                }
                // 3. 启动 SoftAP 模式
                char ap_ssid[] = "xiaohe";
                char ap_password[] = "12345678";
                wifi_service->svr_softap_config(ap_ssid, ap_password);
                wifi_service->trigger_event(WIFI_EVENT_SOFTAP_ENABLE, NULL);
                printf("[DualScreen] 5-click -> SoftAP started: SSID=%s, PASS=%s\n", ap_ssid, ap_password);
                LabelView_left->setVisible(false);
                LabelView_right->setVisible(false);
                LabelView_left_word->setVisible(true);
                LabelView_right_word->setVisible(true);
                wifi_config_mode = 1;
            }
              
        }
        
    }
}

static void dualscreen_ai_entry(void)
{
    install_app(&dualscreen_ai_app);
}

